function evaluateFormula(template: string, data: Record<string, any>): any {
  // Extract formula from template (e.g., '{{price * quantity}}' -> 'price * quantity')
  const formulaMatch = template.match(/\{\{(.*?)\}\}/);

  if (!formulaMatch) {
    return template;
  }

  const formula = formulaMatch[1];

  // Create a function that has access to the data context
  const evaluator = new Function(...Object.keys(data), `return ${formula}`);

  // Call the function with the data values
  const result = evaluator(...Object.values(data));

  return result;
}

// Test examples
const documentData = {
  price: 100,
  quantity: 5,
  taxRate: 0.1,
  discount: 10
};

console.log(evaluateFormula('{{price * quantity}}', documentData));
// Output: 500

console.log(evaluateFormula('{{price * quantity * (1 + taxRate)}}', documentData));
// Output: 550

console.log(evaluateFormula('{{(price * quantity) - discount}}', documentData));
// Output: 490

console.log(evaluateFormula('Total: ${{(price * quantity - discount) * (1 + taxRate)}}', documentData));
// Output: Total: $539

console.log(evaluateFormula('{{Math.round(price * quantity * 0.85)}}', { ...documentData, Math }));
// Output: 425

// Multiple formulas in one template
function evaluateMultipleFormulas(template: string, data: Record<string, any>): string {
  return template.replace(/\{\{(.*?)\}\}/g, (match, formula) => {
    const evaluator = new Function(...Object.keys(data), `return ${formula}`);
    const result = evaluator(...Object.values(data));
    return result;
  });
}

