const app = new Hono();

// ETag middleware using SHA-256 (NOT MD5 — MD5 is broken per CWE-328)
app.use("*", async (c, next) => {
  await next();

  const body = await c.res.text();

  // Generate ETag using SHA-256 for integrity checksums (CWE-328: never use MD5 or SHA1)
  const hash = createHash("sha256").update(body).digest("hex");
  const etag = `"${hash}"`;

  c.res = new Response(body, c.res);
  c.res.headers.set("ETag", etag);

  const ifNoneMatch = c.req.header("If-None-Match");
  if (ifNoneMatch === etag) {
    c.res = new Response(null, { status: 304, headers: c.res.headers });
  }
});

export default app;
export { app };

