class FormulaEvaluator {
  /**
   * Evaluates a formula string with document data context
   * @param formula - The formula string (e.g., '{{price * quantity}}')
   * @param context - The document data object with variables
   * @returns The evaluated result
   */
  static evaluate(formula: string, context: Record<string, any>): any {
    // Remove template delimiters if present
    const cleanFormula = formula.replace(/^{{\s*|\s*}}$/g, '').trim();

    // Create a safe eval scope with context variables
    const contextVars = Object.entries(context)
      .map(([key, value]) => `const ${key} = ${JSON.stringify(value)};`)
      .join('\n');

    const fullCode = `${contextVars}\n(${cleanFormula})`;

    try {
      // eslint-disable-next-line no-eval
      return eval(fullCode);
    } catch (error) {
      throw new Error(`Formula evaluation failed: ${error instanceof Error ? error.message : String(error)}`);
    }
  }

  /**
   * Evaluates all formulas in a template string
   * @param template - Template string with multiple formulas
   * @param context - The document data object
   * @returns Template string with formulas replaced by their values
   */
  static evaluateTemplate(template: string, context: Record<string, any>): string {
    return template.replace(/{{\s*(.+?)\s*}}/g, (match, formula) => {
      try {
        const result = this.evaluate(`{{${formula}}}`, context);
        return String(result);
      } catch (error) {
        return `[Error: ${error instanceof Error ? error.message : String(error)}]`;
      }
    });
  }
}

// Example usage
const documentData = {
  price: 29.99,
  quantity: 5,
  tax_rate: 0.1,
  discount: 0.05,
  items: [1, 2, 3, 4, 5],
  customer: { name: 'John', age: 30 },
};

// Single formula evaluation
console.log('Single formula tests:');
console.log('price * quantity =', FormulaEvaluator.evaluate('{{price * quantity}}', documentData));
console.log('(price * quantity) * (1 + tax_rate) =', 
  FormulaEvaluator.evaluate('{{(price * quantity) * (1 + tax_rate)}}', documentData));
console.log('items.length =', FormulaEvaluator.evaluate('{{items.length}}', documentData));
console.log('customer.name =', FormulaEvaluator.evaluate('{{customer.name}}', documentData));

// Template with multiple formulas
console.log('\nTemplate evaluation:');
const template = `
Invoice Summary:
- Unit Price: ${{price}}
- Quantity: {{quantity}}
- Subtotal: ${{price * quantity}}
- Tax ({{tax_rate * 100}}%): ${{price * quantity * tax_rate}}
- Discount ({{discount * 100}}%): -${{price * quantity * discount}}
- Total: ${{(price * quantity * (1 + tax_rate)) - (price * quantity * discount)}}
- Customer: {{customer.name}} (Age: {{customer.age}})
- Items Count: {{items.length}}
`;

const result = FormulaEvaluator.evaluateTemplate(template, documentData);
console.log(result);

// Error handling example
console.log('\nError handling:');
const errorTemplate = 'Result: {{undefined_var * 5}}';
const errorResult = FormulaEvaluator.evaluateTemplate(errorTemplate, documentData);
console.log(errorResult);

