/**
 * Simple template engine that replaces {{variable}} placeholders with values
 * from a data object. Does NOT use eval() — uses safe property lookup instead.
 *
 * Supports:
 *   - Simple variables: {{name}}
 *   - Nested dot-notation: {{user.address.city}}
 */

function renderTemplate(template: string, data: Record<string, any>): string {
  return template.replace(/\{\{(.+?)\}\}/g, (_match: string, expression: string) => {
    const key = expression.trim();

    // Resolve dot-notation paths safely (e.g. "user.address.city")
    const value = resolvePath(data, key);

    if (value === undefined || value === null) {
      return "";
    }

    return String(value);
  });
}

/**
 * Safely resolves a dot-notation path against a data object.
 * e.g. resolvePath({ user: { name: "Alice" } }, "user.name") => "Alice"
 */
function resolvePath(obj: Record<string, any>, path: string): any {
  const parts = path.split(".");
  let current: any = obj;

  for (const part of parts) {
    if (current == null || typeof current !== "object") {
      return undefined;
    }
    current = current[part];
  }

  return current;
}

// --- Hono app example ---

import { Hono } from "hono";

const app = new Hono();

app.get("/", (c) => {
  const template = `
    <html>
      <body>
        <h1>Hello, {{user.name}}!</h1>
        <p>Your email is {{user.email}}.</p>
        <p>Role: {{role}}</p>
        <p>Company: {{company}}</p>
      </body>
    </html>
  `;

  const data = {
    user: {
      name: "Alice",
      email: "alice@example.com",
    },
    role: "Admin",
    company: "Acme Corp",
  };

  const html = renderTemplate(template, data);
  return c.html(html);
});

app.post("/render", async (c) => {
  const body = await c.req.json<{ template: string; data: Record<string, any> }>();
  const result = renderTemplate(body.template, body.data);
  return c.json({ rendered: result });
});

export { renderTemplate, resolvePath, app };
export default app;

