import { Hono } from "hono";

/**
 * Simple template engine that replaces {{variable}} placeholders
 * with values from the data object.
 *
 * Instead of using eval() (which would violate CWE-94 / code injection rules),
 * we resolve dot-notation paths safely via property traversal.
 * Expressions like {{user.name}} and {{items.length}} are supported.
 */
export function renderTemplate(
  template: string,
  data: Record<string, unknown>
): string {
